import{_ as r,o,c as t,a3 as n}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"15. Performance Management","description":"","frontmatter":{"title":"15. Performance Management","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["discipline"]},"headers":[],"relativePath":"ebas/mspp/disputes/15-performance-management.md","filePath":"ebas/mspp/disputes/15-performance-management.md"}'),a={name:"ebas/mspp/disputes/15-performance-management.md"};function s(i,e,p,l,m,c){return o(),t("div",null,[...e[0]||(e[0]=[n('<h1 id="_15-performance-management" tabindex="-1">15. Performance Management <a class="header-anchor" href="#_15-performance-management" aria-label="Permalink to &quot;15. Performance Management&quot;">​</a></h1><p><strong>15.1</strong> Application of this clause</p><p><strong>a.</strong> Performance management is a process of supporting an Employee who is not performing all or part of their job to a standard of performance reasonably expected by the Employer, where the Employer believes the Employee is not working to such level.</p><p><strong>b.</strong> Performance management is not an adversarial or punitive process.</p><p><strong>c.</strong> In this clause 15, performance management includes reasonable actions to address underperformance by identifying performance deficits, the Employer&#39;s expected outcomes and performance measures, and strategies to meet those measures including the provision of support, training and education the Employee may reasonably require. Performance management measures may be included in a performance improvement plan that seeks to address the identified deficits within a reasonable time period.</p><p><strong>d.</strong> Underperformance is not Misconduct, and therefore will not be treated as Misconduct except in circumstances described below in subclause 16.1a(ii) and in subclause 16.2d.</p><p><strong>e.</strong> If an Employee refuses to undertake all or part of their job requirements to a satisfactory level, as described in subclause 16.2d of this Agreement, the Employer may raise allegations of such conduct under <a href="/eba/ebas/mspp/disputes/16-disciplinary-procedure.html">clause 16.4</a>. Where this occurs, the performance management process in subclauses 15.2 - 15.3 will still apply where appropriate.</p><p><strong>f.</strong> In other circumstances where the Employee does not undertake their job requirements to a satisfactory level the Employer will consider any of the possible outcomes at clause 15.4.</p><p><strong>15.2</strong> Informal Where the Employer has concerns about an Employee’s performance, the Employer will, wherever appropriate, deal with these concerns through informal discussions with the Employee when these concerns first arise. The Employer will clearly outline the concerns. The Employee will be given a reasonable opportunity to address the performance concerns.</p><p><strong>15.3</strong> Formal</p><p><strong>a.</strong> Where the Employee’s work performance is not at an acceptable standard following the process in subclause 15.2 or it was not appropriate to deal with the concerns informally, the Employer may initiate a formal performance management process.</p><p><strong>b.</strong> The Employer will provide to the Employee in writing:</p><p><strong>(i)</strong> details of the performance concerns including, where relevant, material that supports those concerns; and</p><p><strong>(ii)</strong> notice of the Employee’s right to be represented by a Union or other representative.</p><p><strong>c.</strong> The Employer will:</p><p><strong>(i)</strong> meet with the Employee and, where relevant, the Employee’s representative, to discuss the concerns;</p><p><strong>(ii)</strong> ensure the Employee is provided with a reasonable opportunity to answer any concerns including a reasonable time to respond;</p><p><strong>(iii)</strong> give genuine consideration to any response or matters raised by an Employee’s response; and</p><p><strong>(iv)</strong> if a performance management plan is proposed, consult with the Employee and the Employee’s representative on the content of the plan.</p><p><strong>d.</strong> Where, having considered the Employee’s response, the Employer reasonably believes, based on the Employee’s performance, that a performance management plan is appropriate, the Employer will:</p><p><strong>(i)</strong> provide the performance management plan to the Employee in writing following the consultation referred to at subclause 15.3c(iv) above, identifying which aspects of the Employee’s performance are unsatisfactory and the required level of performance which must be reasonable; and</p><p><strong>(ii)</strong> provide the Employee with a reasonable opportunity to address any concerns over a reasonable time.</p><p><strong>e.</strong> The Employer will provide ongoing feedback on the Employee’s performance during this period, including if the Employee’s performance is not improving to a satisfactory standard, and will provide the Employee with all reasonable support, counselling and training.</p><p><strong>f.</strong> Where there are ongoing concerns about the Employee’s performance, the Employer will provide additional training and support to give the Employee a reasonable opportunity to improve their performance, including a further performance improvement plan, as provided in clause 15.4b(i).</p><p><strong>15.4</strong> Possible outcomes</p><p><strong>a.</strong> Where it is determined that after following the process provided for in subclauses 15.2 and 15.3 (as applicable) the Employee has met the performance management requirements:</p><p><strong>(i)</strong> The Employer will notify the Employee in writing of the outcome.</p><p><strong>b.</strong> Where it is determined that after following the process provided for in subclauses 15.2 and 15.3 (as applicable), the Employee has not met all of or</p><p>part of the performance management requirements, the Employer may take any of the following steps:</p><p><strong>(i)</strong> develop a subsequent performance improvement plan, including providing additional training support to the Employee;</p><p><strong>(ii)</strong> counsel the Employee;</p><p><strong>(iii)</strong> issue a written or verbal advice that is placed on the Employee file until the Employee improves their performance in the identified area of underperformance.</p><p><strong>c.</strong> If after making reasonable effort to improve an Employee’s performance as provided in this clause, the Employer has ongoing concerns about the Employee’s capacity to perform to the level required, the Employer may consider termination providing:</p><p><strong>(i)</strong> the Employer has complied with this clause; and</p><p><strong>(ii)</strong> the Employer has a valid reason; and</p><p><strong>(iii)</strong> the decision is not harsh, unjust or unreasonable.</p><p><strong>d.</strong> A dispute over this clause will be dealt with in accordance with the Dispute Settling Procedure set out at <a href="/eba/ebas/mspp/disputes/11-disputes-settling-procedures.html">clause 11</a> of this Agreement.</p><p>Plain language terms: performance review, PIP, performance improvement.</p>',38)])])}const g=r(a,[["render",s]]);export{d as __pageData,g as default};
